import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

interface ApiEndpoints {
  @GET("/users")
  suspend fun getUsers(): List<UserProfile>
}

data class UserProfile(val id: String, val name: String)

enum class Environment(val url:String){
  DEV("https://dev.api.example.com"),
  STAGE("https://stage.api.example.com"),
  PROD("https://api.example.com")
}

class NetworkModule(private val environment: Environment, private val authToken: String) {

  private val httpClient by lazy {

    val logging = HttpLoggingInterceptor().apply {
      level = HttpLoggingInterceptor.Level.BODY
    }

    OkHttpClient.Builder()
      .addInterceptor { chain ->
        val request = chain
          .request()
          .newBuilder()
          .addHeader("Authorization", "Bearer $authToken")
          .build()
        chain.proceed(request)
      }
      .addInterceptor(logging)
      .build()
  }

  private val retrofit by lazy {
    Retrofit.Builder()
      .baseUrl(environment.url)
      .client(httpClient)
      .addConverterFactory(GsonConverterFactory.create())
      .build()
  }

  val api: ApiEndpoints by lazy {
    retrofit.create(ApiEndpoints::class.java)
  }

}